insert into public.lore_entries (slug, title, category, content, pathway, epoch, city, npcs, sequences, tags, token_count)
values
  ('tarot-club-roster', 'The Tarot Club — The Circle of Cards', 'organization', 'The Tarot Club''s members are known to one another only by the cards they hold. It was founded by three — The Fool (its masked, fate-wrapped convener), Justice, and The Hanged Man — and grew into a small circle of Major Arcana: Justice is Audrey Hall, a Visionary noblewoman of Backlund; The Hanged Man is Alger Wilson, a sea-faring Beyonder of the storm-faith who began on the Tyrant path; The Sun is Derrick Berg of the City of Silver; The Magician is Fors Wall of the old Abraham line, who walks the Door; The Moon is Emlyn White, a Sanguine of the scarlet moon; The Hermit is Cattleya, a pirate-queen of the far seas; The Star is Leonard Mitchell, a Darkness Beyonder of the Evernight Church; and Judgment is the justiciar Xio Derecha. They never see one another''s true faces unless they choose, and trade intelligence, ingredients, and formulas none could gather alone. Two cautions for any who study them: "The World" is no separate member but the Fool''s own second seat, and the outside churches'' belief that "Death" sits among them is a false rumour the Star planted on purpose.', null, 5, null, ARRAY['Audrey Hall', 'Alger Wilson', 'Derrick Berg', 'Fors Wall', 'Emlyn White', 'Cattleya', 'Leonard Mitchell'], ARRAY[4], ARRAY['tarot-club', 'the-fool', 'secret-organization', 'roster', 'spoiler'], 255),
  ('twilight-hermit-order', 'The Twilight Hermit Order', 'organization', 'The Twilight Hermit Order is one of the two secret powers said to rival the orthodox churches and the royal families — and the more shadowed of the two. It was founded by Adam, the eldest son of the Ancient Sun God, and it works toward a single hidden end: to guide history from behind the curtain so that the Original Creator, the fallen Ancient Sun God, may one day resurrect. It keeps a Second Blasphemy Slate, the slab that records all twenty-two pathways, and it asks its initiates to take up the Visionary, Sun, White Tower, or Tyrant paths unless they come already Beyonders of another. Its true strength is placement: its members sit in high offices of the churches, the militaries, and the noble houses, and from there they nudge wars, assassinations, and ascensions to fall as the Order wills. It gathers in a dreamscape that spans the continent, bears an old grudge against the True Creator, and guards its name so jealously that to speak it aloud is to invite quiet elimination. Among those it has counted are the transmigrator-emperor Roselle Gustav and the Visionary Hermes.', null, 5, null, ARRAY['Roselle Gustav', 'Hermes'], ARRAY[4], ARRAY['twilight-hermit-order', 'ancient-sun-god', 'secret-organization', 'blasphemy-slate', 'spoiler'], 255),
  ('demoness-sect', 'The Demoness Sect', 'organization', 'The Demoness Sect is the present-day heir of the Fourth-Epoch Demoness Family, and it controls the Demoness Pathway. It worships the Primordial Demoness, the being its doctrine holds to be the true inheritor of the Creator — the first thing born of the Chaos and the last Ender of all things. Its matriarch is Judith, the Demoness of Gray, daughter of the Blood Emperor Alista Tudor and the Primordial Demoness herself. The Sect is, by the nature of its path, wholly female: fathers and sons alike are made women as they climb the Demoness sequences, daughters who cannot walk it are given away, and — strangest of all — it despises and destroys any true-born female Demoness it finds, for the Primordial Demoness suffers no rival. Its affairs are run by thirteen high Demonesses each titled by a colour, a name earned only on reaching the Sequence of Unaging. It is a deadly enemy of the Tarot Club; in the end, after the Primordial Demoness falls, its remnants are folded into the Church of the Ruler of Calamity.', null, 5, null, ARRAY['Judith'], ARRAY[4], ARRAY['demoness-sect', 'demoness-pathway', 'primordial-demoness', 'secret-organization', 'spoiler'], 250),
  ('abraham-family', 'The Abraham Family', 'organization', 'The Abraham Family was one of the most powerful noble houses of the Fourth-Epoch Tudor Empire, and it holds the full formula of the Door Pathway. Its ancestor was Bethel Abraham — "Mr. Door" — a King of Angels of the Door who, in the elder Warring Era, was reckoned the angel likeliest of all to become a god. For that ambition he was undone: banished into a sealed space of storms and darkness by the Evernight Goddess and the Lord of Storms in the War of the Four Emperors, and his endless cries from that prison became a curse upon his blood, driving his descendants to terrifying madness whenever they reached for the high sequences. Only when Mr. Door finally died did the curse lift. In the present day the surviving family has turned its faith to the Fool and stands among the Church of the Fool; its sign is a set of layered doors drawn in simple lines. It now trains promising outsiders in the Door as well as its own — Fors Wall, the Tarot Club''s Magician, learned her art as a disciple of the family — and it was betrayed from within by the traitor Botis, who carried a stolen relic to the worshippers of the True Creator.', null, 5, null, ARRAY['Bethel Abraham', 'Fors Wall'], ARRAY[4], ARRAY['abraham-family', 'door-pathway', 'angel-family', 'church-of-the-fool', 'spoiler'], 250),
  ('amon-family', 'The Amon Family', 'organization', 'The Amon Family holds the entire formula of the Error Pathway, and it guards a secret stranger than any other house keeps: every member of the family is Amon. They are not kin to their founder but avatars of him — one being wearing many lives — so that to deal with any Amon is to deal with them all. Their ancestor is Amon himself, the Angel of Time, a King of Angels of the Third Epoch and a child of the Ancient Sun God; the family is rumoured a line of blasphemers who claim descent from that dead god. They were broken and scattered in the War of the Four Emperors, weakened ever since. Their emblem is a sign of time — a grey-white disc divided into twelve uneven segments, each half-swallowed in shadow, a black needle laid across it like the hand of a broken clock. To meet an Amon is to suspect that the trickster across the table has met you before, in a face you will never place.', null, 5, null, ARRAY['Amon'], ARRAY[4], ARRAY['amon-family', 'error-pathway', 'angel-family', 'amon', 'spoiler'], 235),
  ('antigonus-family', 'The Antigonus Family', 'organization', 'The Antigonus Family is remembered, where it is remembered at all, by two words: strange, and terrifying. Its founder Antigonus was a descendant of the Annihilation Demonic Wolf Flegrea and brother to the Mother of the Sky, and he raised the ancient Nation of the Evernight on the Fool Pathway before the orthodox powers turned on his house. The Church of the Evernight Goddess destroyed the family utterly. Its ancestor went mad and was sealed away in the Foggy Town atop the Hornacis Mountain Range, where what remained of him became a crawling mass of transparent maggots — for he could not suppress the Primordial will of the Celestial Worthy of Heaven and Earth that woke inside him. The bloodline guttered out entirely with the death of its last descendant, an ordinary man named Ray Bieber, and his mother. The family''s sign is a single vertical eye worked from many thin lines, and to find that mark is reckoned among the worst of omens.', null, 5, null, ARRAY['Antigonus', 'Ray Bieber'], ARRAY[4], ARRAY['antigonus-family', 'fool-pathway', 'angel-family', 'evernight-goddess', 'spoiler'], 240),
  ('augustus-family', 'The Augustus Family', 'organization', 'To the public the Augustus Family is simply the royal house of the Loen Kingdom; in truth it is an Angel Family, controlling the Justiciar and Black Emperor pathways and devoted in secret to the Lord of Storms. It rose from the angel houses of the old Trunsoest Empire: in the wreckage of the War of the Four Emperors it joined the others in splitting the weakened empire and destroying the royal Trunsoest line, then — with the backing of the Lord of Storms and the Evernight Goddess — raised the Loen Kingdom in its place. Its founder and undying ancestor, William Augustus I, still walks among it as one of its living Angels, alongside Dlink Augustus; a third, the Black Emperor George Augustus III, fell in recent years. Its sign is the Sword of Judgment — two ruby-crowned blades pointed down — and its secret hand reaches through the kingdom''s shadow service, MI9. Beneath the crown and the cabinet runs a bloodline far older and more dangerous than any ordinary throne.', null, 5, null, ARRAY['William Augustus I', 'George Augustus III'], ARRAY[4], ARRAY['augustus-family', 'justiciar-pathway', 'black-emperor-pathway', 'angel-family', 'loen-kingdom', 'spoiler'], 250),
  ('andariel-family', 'The Andariel Family', 'organization', 'The Andariel Family was one of the three great Devil families of the Fourth Epoch — with the Nois and the Beria — and it controls the Abyss Pathway. Its ancestors took the bestowment of the Abyss long ago and worship the evil god the lore names the Dark Side of the Universe, and its members are not merely devil-worshippers but Devils in truth, walking the sequences of Serial Killer and Devil. In the ages since its height the family has fallen far, declining into a vassal of the stronger Nois house; in the present day it has thrown in with the Rose School of Thought, and word among Beyonders is that its own leader is dead — given up, they say, as a sacrifice to something larger. Its known sons are few and grim: Devajo Andariel and his nephew Bram. To deal with an Andariel is to deal with the Abyss itself, and few who do so come away unchanged.', null, 5, null, ARRAY['Devajo Andariel', 'Bram Andariel'], ARRAY[4], ARRAY['andariel-family', 'abyss-pathway', 'devil-family', 'rose-school-of-thought', 'spoiler'], 230),
  ('beria-family', 'The Beria Family', 'organization', 'The Beria Family is the second of the Fourth Epoch''s three great Devil families, and like the Andariel it controls the Abyss Pathway and worships the Dark Side of the Universe. "Beria?" a Sanguine once spat at the name — "that crazy family that worships devils? No — they ARE devils." Its members are Devils in the flesh, and its sign is an abstract pentagram crossed with goat''s horns. Like the Andariel it has long since declined into a vassal of the Nois house, its old greatness spent. Its most notable son in the present age is Jason Beria, who wore the face of an ordinary banker named Patrick Jason while serving two hidden masters at once — the blood-soaked Blood Sanctify Sect and the shadow-spinning Twilight Hermit Order, for whom he did quiet, lethal work before his death. Where a Beria''s coin or counsel turns up, an abyssal bargain is rarely far behind.', null, 5, null, ARRAY['Jason Beria'], ARRAY[4], ARRAY['beria-family', 'abyss-pathway', 'devil-family', 'twilight-hermit-order', 'spoiler'], 225),
  ('castiya-family', 'The Castiya Family', 'organization', 'To the public the Castiya Family is the royal house of the Feynapotter Kingdom; in truth it is an Angel Family of the Justiciar Pathway, devoted in secret to the Earth Mother. It began as a lesser noble house of the old Solomon Empire, rose under the Trunsoest, and in the aftermath of the War of the Four Emperors joined the families that destroyed the Trunsoest line — then, with the backing of the Earth Mother and the God of Knowledge and Wisdom, raised the Feynapotter Kingdom for its own. It rules that breadbasket realm to this day. Among its living sons is Camus Castiya, a Justiciar Beyonder who keeps the Earth Mother''s faith far from home in the colonial patrols of the Southern Continent. Beneath the matriarchal crown of Feynapotter runs the old order-keeping power of the Justiciar''s scales, held by a bloodline that has outlasted three empires.', null, 5, null, ARRAY['Camus Castiya'], ARRAY[4], ARRAY['castiya-family', 'justiciar-pathway', 'angel-family', 'feynapotter-kingdom', 'earth-mother', 'spoiler'], 235),
  ('einhorn-family', 'The Einhorn Family', 'organization', 'To the public the Einhorn Family is the imperial house of the Feysac Empire; in truth it is an Angel Family of the Red Priest Pathway, devoted to the God of Combat, and it commands the empire''s navy and its Sonia Sea Fleet. Its ancestor''s soul was bound up long ago with those of Medici and Sauron, the three fusing into a single Red Angel evil spirit; when the Blood Emperor fell, the Einhorn and the Sauron reclaimed their Beyonder inheritance and have been knotted together by marriage ever since. Its living strength is martial and real: the Supreme Commander of the Feysac navy, Awatoma Einhorn, and the imperial-fleet commander Egor Einhorn are of its blood, and Elros Einhorn carries both Einhorn and Sauron lines at once, cousin to the dead Poufer Sauron. Beneath Feysac''s cult of strength and height runs the crimson, conquering power of the Red Priest, held by a house that has made war its faith.', null, 5, null, ARRAY['Awatoma Einhorn', 'Egor Einhorn', 'Elros Einhorn'], ARRAY[4], ARRAY['einhorn-family', 'red-priest-pathway', 'angel-family', 'feysac-empire', 'god-of-combat', 'spoiler'], 250),
  ('eggers-family', 'The Eggers Family', 'organization', 'The Eggers Family was the imperial line of the Balam Empire that ruled the Southern Continent in the Fourth Epoch, and it holds the entire formula of the Death Pathway — for the family are the descendants of Salinger, the death-god the histories call "Death," the first Underworld Emperor. When the orthodox gods slew Salinger and the empire fell, a few surviving Eggers founded the secret Numinous Episcopate to work toward their ancestor''s resurrection. Its sign is the feathered serpent. Its blood runs on in the present in stranger channels than the Episcopate alone: Azik Eggers, the undying Death Consul who once ruled the empire in the flesh, now keeps a far gentler vigil as the Angel of Death under the Fool; Sia Palenque Eggers, the "Pale-White Empress," leads the Episcopate''s Royal Family Faction toward the old throne''s revival; and quieter descendants like Iveljsta Eggers have left the death-road entirely, walking the Chained path among the Fool''s faithful.', null, 5, null, ARRAY['Azik Eggers', 'Sia Palenque Eggers', 'Iveljsta Eggers', 'Salinger'], ARRAY[4], ARRAY['eggers-family', 'death-pathway', 'angel-family', 'numinous-episcopate', 'balam-empire', 'spoiler'], 255),
  ('npc-alger-wilson', 'Alger Wilson — The Hanged Man', 'npc', 'Alger Wilson is one of the three founders of the Tarot Club, where he holds the card of The Hanged Man. A Beyonder of the Rorsted Archipelago''s seas, he began on the Tyrant Pathway — the sea''s own power of storm and water — and later crossed onto the Hanged Man''s road of secrets and fate; he is a man of the storm-faith, tangled with the Church of the Lord of Storms and the drowned worship of the Sonia Sea. Cautious to the point of paranoia and forever short of money, he is nonetheless shrewd, capable, and loyal to the small circle he helped build above the gray fog. He came to the Club as a near-equal of its convener The Fool and the noblewoman Justice, and his far-flung sea-roving makes him its eyes on the eastern ocean and the colonial sea-lanes. To the wider Beyonder world he is no one in particular — a guarded sailor with secrets — which is exactly how he has stayed alive.', null, 5, null, ARRAY['Alger Wilson'], ARRAY[4], ARRAY['tarot-club', 'the-hanged-man', 'tyrant-pathway', 'hanged-man-pathway', 'spoiler'], 215),
  ('npc-fors-wall', 'Fors Wall — The Magician', 'npc', 'Fors Wall is a Beyonder of the Door Pathway, trained as an outside disciple of the ancient Abraham line — the house that holds the full Door formula and has, in this age, turned its faith to the Fool. She is no blood of theirs: her father was a minor military officer, and she came to the Door through the teaching of an Abraham mentor rather than by birth. In the Tarot Club she holds the card of The Magician. A spirited, ambitious, sometimes scatterbrained woman who scrapes a living as a writer and a private tutor of the occult in Backlund, she is braver and more resourceful than her chaotic surface suggests, and her Door artistry — drawing portals, sending messages and objects across distance — makes her quietly invaluable to her circle. She keeps faith with the Church of the Fool. To her neighbours she is an eccentric authoress; to the Tarot Club she is the Magician who can open a way where there is none.', null, 5, null, ARRAY['Fors Wall'], ARRAY[4], ARRAY['tarot-club', 'the-magician', 'door-pathway', 'abraham-family', 'spoiler'], 205),
  ('npc-cattleya', 'Cattleya — The Hermit', 'npc', 'Cattleya is a Beyonder of the Hermit Pathway and, in the Tarot Club, holds the card of The Hermit. Half-Intisian and worldly, she is one of the six great Pirate Kings of the open sea — the "Queen of Stars" at the head of her own fleet — and a ranking Pillar of the secretive Moses Ascetic Order, schooled by the famed Bernadette Gustav. Cool, brilliant, and unflappable, she trades in the rarest Beyonder knowledge and ingredients, and her clairvoyant Hermit arts make her the Club''s far-seeing eye on the seas and the underworld of pirates and smugglers. She holds a particular contempt for the flesh-eating lunatics of the Aurora Order. Beneath the privateer''s swagger she is a scholar of the mysteries as deep as any churchman, and one of the most dangerous women on any ocean — though almost no one she robs ever learns it.', null, 5, null, ARRAY['Cattleya'], ARRAY[4], ARRAY['tarot-club', 'the-hermit', 'hermit-pathway', 'pirate', 'moses-ascetic-order', 'spoiler'], 210),
  ('npc-judith', 'Judith — The Demoness of Gray', 'npc', 'Judith, the Demoness of Gray, is the matriarch of the Demoness Sect and the eldest of the great Demonesses — a being of the Demoness Pathway near the Sequence of Catastrophe. She is the daughter of two ruinous parents: the Blood Emperor Alista Tudor of the Fourth Epoch and the Primordial Demoness herself, and through that blood she has endured across ages as the head of her all-female sect. To her the Primordial Demoness is the true heir of the Creator and the rightful Ender of all things, and she bends the Sect''s thirteen colour-titled Demonesses toward that worship and that ruin. Patient, ancient, and utterly without mercy for rivals — she destroys even true-born female Demonesses on sight — she is among the most dangerous heretics alive, and a sworn enemy of the Tarot Club. Where the Sect''s grey-touched corruption spreads, Judith''s long hand is rarely far behind.', null, 5, null, ARRAY['Judith', 'Alista Tudor'], ARRAY[4], ARRAY['demoness-sect', 'demoness-pathway', 'primordial-demoness', 'matriarch', 'spoiler'], 215),
  ('npc-amon', 'Amon — The Angel of Time', 'npc', 'Amon is the founder and the whole of the Amon Family — for every member of that house is Amon, one being wearing many lives. Once the Angel of Time, a King of Angels of the Third Epoch and a child of the Ancient Sun God, he holds the Error Pathway''s Uniqueness and is named, where he is named at all, the Blasphemer and the God of Trickery. He was born to the rare Sequence of the Worm of Time and has schemed across epochs since, scattered and weakened by the War of the Four Emperors yet never truly beaten. His designs are layered past any single Beyonder''s sight: he plays at fate and probability the way lesser men play at cards, and to bargain with one of his faces is to suspect, too late, that he has met you many times before in masks you will never recognise. He is among the most dangerous beings still walking the world in human shape.', null, 5, null, ARRAY['Amon'], ARRAY[4], ARRAY['amon-family', 'error-pathway', 'angel-of-time', 'trickster', 'spoiler'], 215),
  ('npc-william-augustus', 'William Augustus I — The Undying King', 'npc', 'William Augustus I is the founder and undying ancestor of the Augustus Family, the royal house of the Loen Kingdom — and, in secret, one of its living Angels, a Beyonder near the Sequence of the Hand of Order on the Justiciar Pathway. In the wreckage of the War of the Four Emperors he led the Augustus house, with the backing of the Lord of Storms and the Evernight Goddess, to break the old Trunsoest Empire and raise Loen in its place; centuries later he endures still behind the throne he made, watching over the bloodline and the kingdom both. To the histories he is the legendary first king; to the handful who know the truth he is an Angel of order who has never left, holding the Sword of Judgment over a realm that believes its founder long dead. His will moves through the crown, the cabinet, and the shadow service MI9 alike.', null, 5, null, ARRAY['William Augustus I'], ARRAY[4], ARRAY['augustus-family', 'justiciar-pathway', 'loen-kingdom', 'angel', 'spoiler'], 205),
  ('npc-antigonus', 'Antigonus — The Half-Fool', 'npc', 'Antigonus is the founder and ancestor of the destroyed Antigonus Family, a Beyonder of the Fool Pathway once titled the Half-Fool. He was a descendant of the Annihilation Demonic Wolf Flegrea and brother to the Mother of the Sky, and in the elder ages he raised the Nation of the Evernight and served as a subsidiary god beneath Flegrea. His house earned only two words in the histories — strange, and terrifying — before the Church of the Evernight Goddess destroyed it root and branch. Antigonus himself went mad and was sealed away in the Foggy Town atop the Hornacis Mountain Range, where what is left of him festers as a crawling mass of transparent maggots: he could not suppress the Primordial will of the Celestial Worthy of Heaven and Earth that woke within him. He is less a person now than a sealed catastrophe, a warning of what waits at the top of the Fool''s road for one who reaches too far.', null, 5, null, ARRAY['Antigonus'], ARRAY[4], ARRAY['antigonus-family', 'fool-pathway', 'evernight-goddess', 'sealed', 'spoiler'], 215),
  ('npc-camus-castiya', 'Camus Castiya — Justiciar of Feynapotter', 'npc', 'Camus Castiya — in full, Don Givré Camus Castiya — is a son of the Castiya Family, the Angel house that is both the royal line of the Feynapotter Kingdom and a secret bloodline of the Justiciar Pathway sworn to the Earth Mother. A Justiciar Beyonder of the middle sequences, he keeps the Earth Mother''s faith and the family''s order-keeping discipline far from the Feynapotter heartland, serving in the colonial patrols of the Southern Continent where Feynapotter, Loen, and Intis all press for advantage. Steady, dutiful, and bound by the Justiciar''s instinct for balance and law, he is the kind of quiet operative through whom a great family extends its reach into distant waters. To his fellow officers he is a competent patrol captain of noble birth; what they do not see is the centuries-old Angel Family whose scales he carries into the colonies.', null, 5, null, ARRAY['Camus Castiya'], ARRAY[4], ARRAY['castiya-family', 'justiciar-pathway', 'feynapotter-kingdom', 'earth-mother', 'spoiler'], 205),
  ('npc-elros-einhorn', 'Elros Einhorn — Daughter of Two Houses', 'npc', 'Elros Einhorn carries the blood of two of Feysac''s great Angel houses at once: the Einhorn imperial line and the Sauron family, the two Red Priest houses that have knotted themselves together by marriage for generations. A Red Priest Beyonder of the middle sequences, she is cousin to the late Poufer Sauron and kin to the Weather Warlock Snarner Einhorn, and she moves through the empire''s martial-aristocratic world and the shadowy circles of the Black Cat with equal ease. Proud, capable, and shaped by the God of Combat''s cult of strength like all her house, she embodies the old Einhorn–Sauron alliance in a single person — a living seam between two crimson bloodlines. To Feysac society she is a highborn officer''s daughter; beneath that she is an heir to the Red Priest''s conquering inheritance and the intrigues that bind the empire''s first families.', null, 5, null, ARRAY['Elros Einhorn', 'Awatoma Einhorn'], ARRAY[4], ARRAY['einhorn-family', 'sauron-family', 'red-priest-pathway', 'feysac-empire', 'spoiler'], 205),
  ('npc-iveljsta-eggers', 'Iveljsta Eggers — The Chained Descendant', 'npc', 'Iveljsta Eggers — Monsieur Iveljsta — is a descendant of the Eggers Family, the death-empire bloodline of Salinger, who has turned away from the road his ancestors walked. Where the Eggers hold the full Death-pathway formula and the Numinous Episcopate works to revive the dead god, Iveljsta walks the Chained Pathway instead, near the Sequence of the Wraith, and keeps faith not with the Episcopate''s resurrection but with the Church of the Fool and the Temperance refugees of the Rose School of Thought. He is, in his quiet way, proof that even the bloodline of Death is not bound to its inheritance — a man of an infamous family who chose a different god and a different chain. To those who know the Eggers name he is a surprise and a small hope; to the Episcopate''s zealots, a wayward cousin who would not come home.', null, 5, null, ARRAY['Iveljsta Eggers', 'Salinger'], ARRAY[4], ARRAY['eggers-family', 'chained-pathway', 'church-of-the-fool', 'rose-school-of-thought', 'spoiler'], 205),
  ('npc-jason-beria', 'Jason Beria — The Banker-Devil', 'npc', 'Jason Beria — who wore the respectable name Patrick Jason — was a son of the Beria Family, one of the Fourth Epoch''s three great Devil houses of the Abyss Pathway, and a Devil in the flesh near the Sequence of the Desire Apostle. He hid that nature behind the ledgers of an ordinary banker while serving two hidden masters at once: the blood-soaked Blood Sanctify Sect, and the shadow-weaving Twilight Hermit Order, for whom he did quiet, lethal work — including a hand in the killing the Order arranged through its hired blades. Cold, calculating, and bound to the Dark Side of the Universe his family worships, he is a study in how the old Devil bloodlines survive into a banking age: not with horns and fire, but with a clean office, a friendly smile, and an abyssal bargain waiting under every loan. His death closed one of the Hermit Order''s quieter accounts.', null, 5, null, ARRAY['Jason Beria'], ARRAY[4], ARRAY['beria-family', 'abyss-pathway', 'twilight-hermit-order', 'blood-sanctify-sect', 'spoiler'], 215);
